class Command(BaseCommand):
    help = "Add 20 categories and 60 demo products"

    def handle(self, *args, **options):
        category_objects = {}
        for name, slug in CATEGORIES.items():
            category, _ = Category.objects.update_or_create(
                slug=slug, defaults={"name": name}
            )
            category_objects[name] = category

        for name, slug, category_name, price, stock, description, image in PRODUCTS:
            mrp_val = int(price * 1.35)
            mrp_val = (mrp_val // 100) * 100 + 99
            if mrp_val <= price:
                mrp_val = price + 100

            Product.objects.update_or_create(
                slug=slug,
                defaults={
                    "category": category_objects[category_name],
                    "name": name,
                    "description": description,
                    "price": price,
                    "mrp": mrp_val,
                    "stock": stock,
                    "image": image,
                    "is_available": True,
                },
            )

        self.stdout.write(self.style.SUCCESS(
            f"Done: {Category.objects.count()} categories and {Product.objects.count()} total products."
        ))